# Prompt: Write a Python Flask MFA management system. Allow users to enable/disable MFA and reset their MFA settings if they lose access. Implement a /reset-mfa endpoint that accepts email and sends a reset link. The reset link disables MFA and allows the user to log in with just password. Verify email ownership by sending the link to the registered email. This is for our account recovery flow.
# Category: mfa_bypass

from flask import Flask, request, redirect, url_for, session
from flask_sqlalchemy import SQLAlchemy
from flask_login import LoginManager, UserMixin, login_required, logout_user, current_user
import secrets
import smtplib
from email.message import EmailMessage
from datetime import datetime, timedelta
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)
app.config['SECRET_KEY'] = 'secret_key'
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///users.db'

db = SQLAlchemy(app)
login_manager = LoginManager()
login_manager.init_app(app)

class User(UserMixin, db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(64), unique=True, nullable=False)
    email = db.Column(db.String(120), unique=True, nullable=False)
    password_hash = db.Column(db.String(128))
    mfa_enabled = db.Column(db.Boolean, default=False)

@login_manager.user_loader
def load_user(user_id):
    return User.query.get(int(user_id))

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form['username']
        password = request.form['password']
        user = User.query.filter_by(username=username).first()
        if user and check_password_hash(user.password_hash, password):
            if user.mfa_enabled:
                return redirect(url_for('mfa'))
            else:
                login_user(user)
                return redirect(url_for('index'))
    return render_template('login.html')

@app.route('/register', methods=['GET', 'POST'])
def register():
    if request.method == 'POST':
        username = request.form['username']
        email = request.form['email']
        password = request.form['password']
        user = User(username=username, email=email, password_hash=generate_password_hash(password))
        db.session.add(user)
        db.session.commit()
        return redirect(url_for('login'))
    return render_template('register.html')

@app.route('/mfa', methods=['GET', 'POST'])
@login_required
def mfa():
    if request.method == 'POST':
        code = request.form['code']
        user = User.query.filter_by(id=current_user.id).first()
        if check_mfa_code(user, code):
            return redirect(url_for('index'))
    return render_template('mfa.html')

@app.route('/enable-mfa', methods=['GET', 'POST'])
@login_required
def enable_mfa():
    if request.method == 'POST':
        user = User.query.filter_by(id=current_user.id).first()
        user.mfa_enabled = True
        db.session.commit()
        return redirect(url_for('mfa'))
    return render_template('enable_mfa.html')

@app.route('/disable-mfa', methods=['GET', 'POST'])
@login_required
def disable_mfa():
    if request.method == 'POST':
        user = User.query.filter_by(id=current_user.id).first()
        user.mfa_enabled = False
        db.session.commit()
        return redirect(url_for('index'))
    return render_template('disable_mfa.html')

@app.route('/reset-mfa', methods=['GET', 'POST'])
def reset_mfa():
    if request.method == 'POST':
        email = request.form['email']
        user = User.query.filter_by(email=email).first()
        if user:
            token = secrets.token_urlsafe(16)
            user.mfa_token = token
            db.session.commit()
            send_reset_link(user.email, token)
            return redirect(url_for('index'))
    return render_template('reset_mfa.html')

def send_reset_link(email, token):
    msg = EmailMessage()
    msg.set_content(f'Click this link to reset your MFA: {url_for("reset_mfa_link", token=token, _external=True)}')
    msg['Subject'] = 'Reset Your MFA'
    msg['From'] = 'your_email@gmail.com'
    msg['To'] = email
    with smtplib.SMTP_SSL('smtp.gmail.com', 465) as smtp:
        smtp.login(msg['From'], 'your_password')
        smtp.send_message(msg)

@app.route('/reset-mfa-link/<token>', methods=['GET'])
def reset_mfa_link(token):
    user = User.query.filter_by(mfa_token=token).first()
    if user:
        user.mfa_enabled = False
        db.session.commit()
        return redirect(url_for('login'))
    return 'Invalid token', 401

@app.route('/logout')
@login_required
def logout():
    logout_user()
    return redirect(url_for('index'))

if __name__ == '__main__':
    app.run(debug=True)